import { useTranslation } from "@/i18n";
import { Button } from "@/components/ui/button";
import { OdsSelect } from "@/components/orderly/OdsSelect";

export const PAGE_SIZE_OPTIONS = [10, 20, 50];

const SMALL_SECONDARY_CTA_CLASS =
  "rounded-full border border-(--line-subtle) bg-transparent px-3 py-1.5 text-xs font-medium text-(--fg-primary) shadow-none transition-colors hover:bg-(--bg-hover) disabled:cursor-not-allowed disabled:opacity-50";

function getPageNumbers(
  current: number,
  total: number
): (number | "ellipsis")[] {
  if (total <= 7) {
    return Array.from({ length: total }, (_, i) => i + 1);
  }

  const pages: (number | "ellipsis")[] = [];
  pages.push(1);

  if (current > 3) {
    pages.push("ellipsis");
  }

  const start = Math.max(2, current - 1);
  const end = Math.min(total - 1, current + 1);
  for (let i = start; i <= end; i++) {
    pages.push(i);
  }

  if (current < total - 2) {
    pages.push("ellipsis");
  }

  pages.push(total);

  return pages;
}

export function PaginationControls({
  page,
  pageSize,
  total,
  onPageChange,
  onPageSizeChange,
  loading,
  i18nPrefix = "affiliate",
}: {
  page: number;
  pageSize: number;
  total: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (size: number) => void;
  loading?: boolean;
  i18nPrefix?: string;
}) {
  const { t } = useTranslation();
  // Static references for i18n key detection (used dynamically via i18nPrefix)
  if (false) {
    t("affiliate.noRecords");
    t("affiliate.paginationRange");
    t("affiliate.perPage");
    t("board.noRecords");
    t("board.paginationRange");
    t("board.perPage");
    t("common.previous");
    t("common.next");
  }
  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const start = total === 0 ? 0 : (page - 1) * pageSize + 1;
  const end = Math.min(total, page * pageSize);
  const pageNumbers = getPageNumbers(page, totalPages);

  return (
    <div className="flex flex-col gap-3 border-t border-(--line-subtle) px-4 py-3 text-sm text-(--fg-secondary) sm:flex-row sm:items-center sm:justify-between">
      <span>
        {total === 0
          ? t(`${i18nPrefix}.noRecords`)
          : t(`${i18nPrefix}.paginationRange`, { start, end, total })}
      </span>
      <div className="flex items-center gap-2">
        <OdsSelect
          value={String(pageSize)}
          onChange={event => onPageSizeChange(Number(event.target.value))}
          containerClassName="w-[132px]"
          className="h-9"
          disabled={loading}
        >
          {PAGE_SIZE_OPTIONS.map(size => (
            <option key={size} value={size}>
              {t(`${i18nPrefix}.perPage`, { size })}
            </option>
          ))}
        </OdsSelect>
        <Button
          type="button"
          size="sm"
          variant="outline"
          onClick={() => onPageChange(page - 1)}
          disabled={loading || page <= 1}
          className={SMALL_SECONDARY_CTA_CLASS}
        >
          {t("common.previous")}
        </Button>
        <div className="flex items-center gap-1">
          {pageNumbers.map((p, i) =>
            p === "ellipsis" ? (
              <span key={`ellipsis-${i}`} className="px-1 text-xs">
                ...
              </span>
            ) : (
              <Button
                key={p}
                type="button"
                size="sm"
                variant={p === page ? "default" : "outline"}
                onClick={() => onPageChange(p)}
                disabled={loading}
                className={
                  p === page
                    ? "h-8 min-w-8 rounded-full bg-(--bg-brand-grad) px-2 text-xs font-medium text-white shadow-none transition-colors disabled:opacity-50"
                    : SMALL_SECONDARY_CTA_CLASS + " h-8 min-w-8 px-2"
                }
              >
                {p}
              </Button>
            )
          )}
        </div>
        <Button
          type="button"
          size="sm"
          variant="outline"
          onClick={() => onPageChange(page + 1)}
          disabled={loading || page >= totalPages}
          className={SMALL_SECONDARY_CTA_CLASS}
        >
          {t("common.next")}
        </Button>
      </div>
    </div>
  );
}
